  ('social-worker-moex-07865', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '張教授研發一種讀書方法來增進學生考社會工作師的成績。張教授運用實驗設計來測試他所研發的讀書方 法。請問，該實驗設計的預測應為：', '["02應該比01的分數高", "02應該比04的分數高", "04應該比03的分數高", "04應該比01的分數高 R＝隨機分派  R  01  X   02 0＝考試成績  R  03  04 X＝讀書方法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07866', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在寫研究報告時，應如何避免抄襲（plagiarism）？', '["重新改寫另一位作者的話，把改寫後的字句當作自己的言論", "把另一位作者的話一字不漏的引用，並當作是自己的言論", "將另一位作者的想法當成自己的想法發表", "在引用其他人的著作時，應清楚地說明誰說了什麼，並指出引文的出處"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07867', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究假設為：社會工作的介入（intervention）可以減少學生輟學率。研究結果發現，社會工作的介入只 能減少家庭壓力較大的學生的輟學率。請問，家庭壓力的大小在此研究中，是屬於何種變項？', '["自變項（independent variable）", "依變項（dependent variable）", "調節變項（moderating variable）", "可以當作自變項，也可以當作依變項"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07868', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '承上題，請問「社會工作的介入」是屬於何種變項？', '["自變項（independent variable）", "依變項（dependent variable）", "調節變項（moderating variable）", "可以當作自變項，也可以當作依變項"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07869', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究發現，案主尋求協助的原因與社工員提供服務的目標越能配合，則案主對該服務的滿意度越高。 該研究結果顯示此兩個變項之間的關係為：', '["正相關", "負相關", "曲線相關", "沒有相關"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
